  .toggle-switch input { opacity: 0; width: 0; height: 0; }
  .toggle-track {
    position: absolute;
    inset: 0;
    border-radius: 10px;
    background: var(--border2);
    cursor: pointer;
    transition: background 0.2s;
  }
  .toggle-track::after {
    content: '';
    position: absolute;
    left: 2px; top: 2px;
    width: 16px; height: 16px;
    border-radius: 50%;
    background: var(--muted);
    transition: transform 0.2s, background 0.2s;
  }
  .toggle-switch input:checked + .toggle-track { background: rgba(91,142,240,0.3); }
  .toggle-switch input:checked + .toggle-track::after { transform: translateX(16px); background: var(--accent); }
  .toggle-label { font-size: 11px; color: var(--muted); }
  .toggle-label span { color: var(--text); font-weight: 500; }

  .model-tag-row { display: flex; flex-wrap: wrap; gap: 5px; }
  .model-tag {
    font-size: 10px;
