  .model-tag:hover, .model-tag.active { border-color: var(--accent); color: var(--accent); background: rgba(91,142,240,0.08); }

  .divider { height: 1px; background: var(--border); margin: 2px 0; }

  /* Success criteria section in panel */
  .criteria-row { display: flex; gap: 8px; align-items: center; }
  .criteria-select {
    background: var(--surface2);
    border: 1px solid var(--border2);
    border-radius: 5px;
    color: var(--text);
    font-family: var(--font-mono);
    font-size: 11px;
    padding: 5px 6px;
    outline: none;
    cursor: pointer;
    width: 130px;
  }
  .criteria-val {
    flex: 1;
    background: var(--surface2);
    border: 1px solid var(--border2);
    border-radius: 5px;
    color: var(--text);
    font-family: var(--font-mono);
    font-size: 11px;
    padding: 5px 8px;
    outline: none;
    width: 60px;
  }
  .criteria-select:focus, .criteria-val:focus { border-color: var(--accent); }

  /* Empty canvas state */
  .empty-canvas {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 100%;
    gap: 12px;
    color: var(--muted);
    pointer-events: none;
  }
  .empty-canvas-icon { font-size: 36px; opacity: 0.3; }
  .empty-canvas-text { font-size: 12px; opacity: 0.5; letter-spacing: 0.3px; }

  /* Stateless badge on node */
  .stateless-badge {
    font-size: 8px;
    padding: 2px 5px;
    border-radius: 3px;
    background: rgba(45,212,191,0.1);
    border: 1px solid rgba(45,212,191,0.3);
    color: var(--teal);
    font-weight: 600;
    letter-spacing: 0.5px;
    margin-top: 2px;
    display: inline-block;
  }

  /* Toast */
  .toast {
    position: fixed;
    bottom: 24px;
    right: 24px;
    background: var(--surface2);
    border: 1px solid var(--border2);
    border-radius: 8px;
    padding: 10px 16px;
    font-size: 12px;
    color: var(--text);
    opacity: 0;
    transform: translateY(8px);
    transition: all 0.2s;
    pointer-events: none;
    z-index: 100;
  }
  .toast.show { opacity: 1; transform: translateY(0); }
  .toast.success { border-color: rgba(62,207,142,0.4); }

  /* Scrollbar */
  ::-webkit-scrollbar { width: 5px; height: 5px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 3px; }
</style>
