    </div>

    <div class="sidebar-section">
      <div class="sidebar-label">models</div>
      <div class="model-tag-row">
        <span class="model-tag active">claude-sonnet</span>
        <span class="model-tag">claude-opus</span>
        <span class="model-tag">gpt-4o</span>
        <span class="model-tag">gemini-2.5</span>
        <span class="model-tag">local</span>
