</div>

<div class="toast" id="toast"></div>

<script>
const ROLE_DEFAULTS = {
  planner: {
    label: 'Planner',
    color: '#9b7ef8',
    badge: 'SDD',
    badgeStyle: 'background:rgba(155,126,248,0.1);color:#9b7ef8;border:1px solid rgba(155,126,248,0.3)',
    inputs: [{name:'prompt', type:'prompt'}],
    outputs: [{name:'spec.md', type:'md'}],
    stateless: false,
    model: 'claude-sonnet',
    system_prompt: 'You are a senior technical planner. Given a user prompt, produce a detailed markdown specification including goals, acceptance criteria, and technical constraints.',
    success_criteria: 'reviewer_approved',
    max_iter: 5
  },
  developer: {
    label: 'Developer',
    color: '#3ecf8e',
    badge: 'DEV',
    badgeStyle: 'background:rgba(62,207,142,0.1);color:#3ecf8e;border:1px solid rgba(62,207,142,0.3)',
    inputs: [{name:'spec.md', type:'md'}],
    outputs: [{name:'code', type:'code'}, {name:'github_pr', type:'github'}],
    stateless: false,
    model: 'claude-sonnet',
    system_prompt: 'You are an expert software developer. Implement the spec faithfully. Write clean, tested, documented code.',
    success_criteria: 'tests_pass',
    max_iter: 8
  },
  tester: {
    label: 'Tester',
    color: '#f5a623',
    badge: 'QA',
    badgeStyle: 'background:rgba(245,166,35,0.1);color:#f5a623;border:1px solid rgba(245,166,35,0.3)',
    inputs: [{name:'code', type:'code'}],
    outputs: [{name:'test_report.md', type:'tests'}, {name:'score', type:'score'}],
    stateless: false,
    model: 'claude-sonnet',
    system_prompt: 'You are a QA engineer. Write and run tests. Return a structured test report with pass/fail counts and a quality score 0-100.',
    success_criteria: 'score >= 80',
    max_iter: 3
  },
  reviewer_stateless: {
    label: 'Reviewer',
    color: '#2dd4bf',
    badge: '∅',
    badgeStyle: 'background:rgba(45,212,191,0.1);color:#2dd4bf;border:1px solid rgba(45,212,191,0.3)',
    inputs: [{name:'code', type:'code'}, {name:'spec.md', type:'md'}],
    outputs: [{name:'feedback.md', type:'feedback'}, {name:'approved', type:'score'}],
    stateless: true,
    model: 'claude-sonnet',
    system_prompt: 'You are a fresh code reviewer with no prior context. Review the code against the spec. Return structured feedback and a binary approved/rejected decision.',
    success_criteria: 'approved == true',
    max_iter: 5
  },
  reviewer_stateful: {
    label: 'Reviewer',
    color: '#e85d75',
    badge: '●',
    badgeStyle: 'background:rgba(232,93,117,0.1);color:#e85d75;border:1px solid rgba(232,93,117,0.3)',
    inputs: [{name:'code', type:'code'}, {name:'prev_feedback', type:'feedback'}],
    outputs: [{name:'feedback.md', type:'feedback'}, {name:'score', type:'score'}],
    stateless: false,
    model: 'claude-sonnet',
    system_prompt: 'You are a senior reviewer tracking this feature over multiple iterations. Consider prior feedback history and track improvement trend.',
    success_criteria: 'score >= 85',
    max_iter: 5
  },
  custom: {
    label: 'Custom role',
    color: '#6b7490',
    badge: 'NEW',
    badgeStyle: 'background:rgba(107,116,144,0.1);color:#6b7490;border:1px solid rgba(107,116,144,0.3)',
    inputs: [{name:'input', type:'prompt'}],
    outputs: [{name:'output', type:'json'}],
    stateless: false,
    model: 'claude-sonnet',
    system_prompt: '',
    success_criteria: 'reviewer_approved',
    max_iter: 5
  }
};

const IO_TYPES = ['prompt','md','code','github','tests','report','feedback','json','score'];
const TAG_CLASS = { prompt:'tag-prompt', md:'tag-md', code:'tag-code', github:'tag-github', tests:'tag-tests', report:'tag-report', feedback:'tag-feedback', json:'tag-json', score:'tag-score' };
const MODELS = ['claude-sonnet','claude-opus','gpt-4o','gemini-2.5','local'];
const SUCCESS_OPTIONS = ['reviewer_approved','tests_pass','score >= 80','score >= 85','score >= 90','no_errors','approved == true','custom'];

let nodes = [];
let selectedId = null;
let dragRole = null;
let idCounter = 0;

function uid() { return 'node_' + (++idCounter); }

function dragStart(e, role) { dragRole = role; }
function allowDrop(e) { e.preventDefault(); }
function drop(e) { e.preventDefault(); if (dragRole) { addRoleToCanvas(dragRole); dragRole = null; } }

function addRoleToCanvas(role) {
  const def = JSON.parse(JSON.stringify(ROLE_DEFAULTS[role]));
  def.id = uid();
  def.role = role;
  nodes.push(def);
  renderCanvas();
  selectNode(def.id);
  hideEmpty();
  showToast(`${def.label} added to pipeline`);
}

function deleteNode(id) {
  nodes = nodes.filter(n => n.id !== id);
  if (selectedId === id) { selectedId = null; closeDetail(); }
  renderCanvas();
  if (!nodes.length) showEmpty();
}

function selectNode(id) {
  selectedId = id;
  renderCanvas();
  const node = nodes.find(n => n.id === id);
  if (node) openDetail(node);
}

function renderCanvas() {
  const flow = document.getElementById('pipelineFlow');
  flow.innerHTML = '';

  nodes.forEach((node, i) => {
    if (i > 0) {
      const conn = document.createElement('div');
      conn.className = 'connector';
      conn.style.height = '80px';
      conn.innerHTML = `
        <div class="connector-line"></div>
        <div class="connector-arrow"></div>
        ${i > 0 && nodes[i].stateless ? `<div class="connector-feedback"></div><div class="connector-feedback-label">↩ on reject</div>` : ''}
      `;
      flow.appendChild(conn);
    }

    const el = document.createElement('div');
    el.className = 'agent-node' + (selectedId === node.id ? ' selected' : '');
    el.onclick = (e) => { e.stopPropagation(); selectNode(node.id); };

    const inputTags = node.inputs.map(io =>
      `<span class="io-tag ${TAG_CLASS[io.type] || 'tag-json'}" title="input">${io.name}</span>`
    ).join('') + `<span class="io-tag add-tag" onclick="event.stopPropagation();addIO('${node.id}','inputs')">+</span>`;

    const outputTags = node.outputs.map(io =>
      `<span class="io-tag ${TAG_CLASS[io.type] || 'tag-json'}" title="output">${io.name}</span>`
    ).join('') + `<span class="io-tag add-tag" onclick="event.stopPropagation();addIO('${node.id}','outputs')">+</span>`;

    el.innerHTML = `
      <div class="agent-node-header">
        <div class="node-dot" style="background:${node.color}"></div>
        <div class="node-title-wrap">
          <div class="node-title">${node.label}</div>
          ${node.stateless ? `<span class="stateless-badge">stateless</span>` : ''}
        </div>
        <span class="node-type-badge" style="${node.badgeStyle}">${node.badge}</span>
        <button class="node-delete" onclick="event.stopPropagation();deleteNode('${node.id}')" title="remove">×</button>
      </div>
      <div class="node-body">
        <div class="io-section">
          <div class="io-label">input</div>
          <div class="io-tags">${inputTags}</div>
        </div>
        <div class="io-section">
          <div class="io-label">output</div>
          <div class="io-tags">${outputTags}</div>
        </div>
      </div>
      <div class="node-footer">
        <span style="font-size:9px;color:var(--muted);margin-right:6px">✓</span>
        <span style="font-size:10px;color:var(--muted);flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${node.success_criteria}</span>
        <span style="font-size:9px;color:var(--muted);margin-left:6px">×${node.max_iter}</span>
      </div>
    `;
    flow.appendChild(el);
  });

  // Add button at end
  const addBtn = document.createElement('button');
  addBtn.className = 'add-node-btn';
  addBtn.innerHTML = '+';
  addBtn.title = 'add role';
  addBtn.onclick = () => showToast('click a role in the sidebar to add it');
  flow.appendChild(addBtn);
}

function addIO(nodeId, direction) {
  const node = nodes.find(n => n.id === nodeId);
  if (!node) return;
  const name = prompt(`New ${direction === 'inputs' ? 'input' : 'output'} name (e.g. spec.md):`);
  if (!name) return;
  node[direction].push({ name: name.trim(), type: 'json' });
  renderCanvas();
  if (selectedId === nodeId) openDetail(node);
}

function openDetail(node) {
  const panel = document.getElementById('detailPanel');
  panel.classList.remove('hidden');
  document.getElementById('detailTitle').textContent = node.label + ' config';

  const body = document.getElementById('detailBody');
  body.innerHTML = `
    <div class="field-group">
      <div class="field-label">role name</div>
      <input class="field-input" value="${node.label}" oninput="updateNode('${node.id}','label',this.value)" />
    </div>

    <div class="field-group">
      <div class="field-label">system prompt</div>
      <textarea class="field-textarea" placeholder="System prompt for this agent…" oninput="updateNode('${node.id}','system_prompt',this.value)">${node.system_prompt}</textarea>
    </div>

    <div class="divider"></div>

    <div class="field-group">
      <div class="field-label">inputs</div>
      <div class="io-editor" id="input-editor-${node.id}">
        ${renderIORows(node, 'inputs')}
      </div>
      <button class="add-io-btn" onclick="addIORow('${node.id}','inputs')">+ add input</button>
    </div>

    <div class="field-group">
      <div class="field-label">outputs</div>
      <div class="io-editor" id="output-editor-${node.id}">
        ${renderIORows(node, 'outputs')}
      </div>
      <button class="add-io-btn" onclick="addIORow('${node.id}','outputs')">+ add output</button>
    </div>

    <div class="divider"></div>

    <div class="field-group">
      <div class="field-label">success criteria</div>
      <div class="criteria-row">
        <select class="criteria-select" onchange="updateCriteria('${node.id}',this.value)">
          ${SUCCESS_OPTIONS.map(o => `<option value="${o}" ${node.success_criteria===o?'selected':''}>${o}</option>`).join('')}
        </select>
      </div>
    </div>

    <div class="field-group">
      <div class="field-label">max iterations</div>
      <input class="field-input" type="number" min="1" max="20" value="${node.max_iter}" style="width:80px" oninput="updateNode('${node.id}','max_iter',parseInt(this.value)||5)" />
    </div>

    <div class="divider"></div>

    <div class="field-group">
      <div class="field-label">memory mode</div>
      <div class="stateless-toggle">
        <label class="toggle-switch">
          <input type="checkbox" ${node.stateless ? 'checked' : ''} onchange="updateNode('${node.id}','stateless',this.checked)">
          <div class="toggle-track"></div>
        </label>
        <div class="toggle-label">
          ${node.stateless
            ? '<span>stateless</span> — fresh context every call'
            : '<span>stateful</span> — accumulates history'}
        </div>
      </div>
    </div>

    <div class="field-group">
      <div class="field-label">model</div>
      <div class="model-tag-row">
        ${MODELS.map(m => `<span class="model-tag ${node.model===m?'active':''}" onclick="updateNode('${node.id}','model','${m}');renderDetail('${node.id}')">${m}</span>`).join('')}
      </div>
    </div>
  `;
}

function renderIORows(node, direction) {
  return node[direction].map((io, idx) => `
    <div class="io-editor-row">
      <input class="io-chip-input" value="${io.name}" placeholder="name" oninput="updateIO('${node.id}','${direction}',${idx},'name',this.value)" />
      <select class="io-type-select" onchange="updateIO('${node.id}','${direction}',${idx},'type',this.value)">
        ${IO_TYPES.map(t => `<option value="${t}" ${io.type===t?'selected':''}>${t}</option>`).join('')}
      </select>
      <button class="remove-io" onclick="removeIO('${node.id}','${direction}',${idx})">×</button>
    </div>
  `).join('');
}

function renderDetail(nodeId) {
  const node = nodes.find(n => n.id === nodeId);
  if (node) openDetail(node);
}

function updateNode(id, key, value) {
  const node = nodes.find(n => n.id === id);
  if (!node) return;
  node[key] = value;
  renderCanvas();
}

function updateIO(nodeId, direction, idx, key, value) {
  const node = nodes.find(n => n.id === nodeId);
  if (!node) return;
  node[direction][idx][key] = value;
  renderCanvas();
  // Re-render just the io editor section without full panel refresh
  const editorEl = document.getElementById(`${direction === 'inputs' ? 'input' : 'output'}-editor-${nodeId}`);
  if (editorEl) editorEl.innerHTML = renderIORows(node, direction);
}

function addIORow(nodeId, direction) {
  const node = nodes.find(n => n.id === nodeId);
  if (!node) return;
  node[direction].push({ name: '', type: 'json' });
  renderCanvas();
  renderDetail(nodeId);
}

function removeIO(nodeId, direction, idx) {
  const node = nodes.find(n => n.id === nodeId);
  if (!node) return;
  node[direction].splice(idx, 1);
  renderCanvas();
  renderDetail(nodeId);
}

function updateCriteria(id, value) {
  const node = nodes.find(n => n.id === id);
  if (!node) return;
  node.success_criteria = value;
  renderCanvas();
}

function closeDetail() {
  selectedId = null;
  document.getElementById('detailPanel').classList.add('hidden');
  renderCanvas();
}

function showEmpty() { document.getElementById('emptyState').style.display = 'flex'; }
function hideEmpty() { document.getElementById('emptyState').style.display = 'none'; }

function showToast(msg, type='') {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'toast show ' + type;
  setTimeout(() => t.classList.remove('show'), 2200);
}

function exportJSON() {
  const data = {
    pipeline: document.getElementById('pipelineName').value,
    max_iterations: parseInt(document.getElementById('maxIter').value),
    agents: nodes.map(n => ({
      id: n.id,
      role: n.role,
      label: n.label,
      stateless: n.stateless,
      model: n.model,
      system_prompt: n.system_prompt,
      inputs: n.inputs,
      outputs: n.outputs,
      success_criteria: n.success_criteria,
      max_iter: n.max_iter
    }))
  };
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url;
  a.download = (data.pipeline || 'pipeline') + '.json'; a.click();
  showToast('pipeline exported as json', 'success');
}

function exportLangGraph() {
  if (!nodes.length) { showToast('add some agents first'); return; }
  const name = document.getElementById('pipelineName').value.replace(/-/g,'_');
  const maxIter = document.getElementById('maxIter').value;

  const agentFns = nodes.map(n => {
    const stateNote = n.stateless ? '# stateless: fresh context, no history injected' : '# stateful: inject prior messages from state';
    return `
def ${n.label.toLowerCase().replace(/\s+/g,'_')}_agent(state: PipelineState) -> PipelineState:
    ${stateNote}
    messages = [] if ${n.stateless} else state.get("messages", [])
    response = llm_call(
        model="${n.model}",
        system="""${n.system_prompt.replace(/"/g,"'")}""",
        inputs={${n.inputs.map(i=>`"${i.name}": state.get("${i.name.replace(/[^a-z0-9]/gi,'_')}")`).join(', ')}},
        stateless=${n.stateless},
    )
    return {
        **state,
        ${n.outputs.map(o=>`"${o.name.replace(/[^a-z0-9]/gi,'_')}": response["${o.name}"]`).join(',\n        ')},
        "messages": [] if ${n.stateless} else state.get("messages",[]) + [response],
        "iteration": state.get("iteration", 0) + 1,
    }`;
  }).join('\n');

  const edgeFns = nodes.map(n => {
    return `
def route_from_${n.label.toLowerCase().replace(/\s+/g,'_')}(state: PipelineState):
    if state.get("iteration", 0) >= ${n.max_iter}:
        return "max_iter_reached"
    if check_criteria(state, "${n.success_criteria}"):
        return "success"
    return "retry"`;
  }).join('\n');

  const graphNodes = nodes.map(n => {
    const fn = n.label.toLowerCase().replace(/\s+/g,'_') + '_agent';
    return `    graph.add_node("${n.label.toLowerCase().replace(/\s+/g,'_')}", ${fn})`;
  }).join('\n');

  const graphEdges = nodes.map((n, i) => {
    const from = n.label.toLowerCase().replace(/\s+/g,'_');
    const next = i < nodes.length-1 ? nodes[i+1].label.toLowerCase().replace(/\s+/g,'_') : 'END';
    return `    graph.add_conditional_edges(
        "${from}",
        route_from_${from},
        {"success": "${next}", "retry": "${from}", "max_iter_reached": "${next}"}
    )`;
  }).join('\n');

  const code = `# Auto-generated by AgentDesk Pipeline Designer
# Pipeline: ${name}
# Max iterations: ${maxIter}

from langgraph.graph import StateGraph, END
from typing import TypedDict, List, Any, Dict

class PipelineState(TypedDict):
    messages: List[Any]
    iteration: int
    ${nodes.flatMap(n=>[...n.inputs,...n.outputs]).map(io=>`${io.name.replace(/[^a-z0-9]/gi,'_')}: Any`).join('\n    ')}

# ─── Agent functions ───────────────────────────────
${agentFns}

# ─── Routing functions ──────────────────────────────
${edgeFns}

def check_criteria(state, criteria):
    if criteria == "reviewer_approved": return state.get("approved") == True
    if criteria == "tests_pass": return state.get("score", 0) >= 80
    if criteria.startswith("score >="):
        threshold = int(criteria.split(">=")[1].strip())
        return state.get("score", 0) >= threshold
    return True

# ─── Build graph ────────────────────────────────────
def build_${name}():
    graph = StateGraph(PipelineState)

${graphNodes}

    graph.set_entry_point("${nodes[0]?.label.toLowerCase().replace(/\s+/g,'_')}")
${graphEdges}

    return graph.compile()

pipeline = build_${name}()
`;

  const blob = new Blob([code], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url;
  a.download = name + '_langgraph.py'; a.click();
  showToast('langgraph python exported', 'success');
}

function savePipeline() {
  const data = { nodes, pipeline: document.getElementById('pipelineName').value };
  localStorage.setItem('agentdesk_pipeline', JSON.stringify(data));
  showToast('pipeline saved', 'success');
}

// Load saved on start
window.addEventListener('load', () => {
  const saved = localStorage.getItem('agentdesk_pipeline');
  if (saved) {
    try {
      const data = JSON.parse(saved);
      nodes = data.nodes || [];
      idCounter = nodes.length;
      if (data.pipeline) document.getElementById('pipelineName').value = data.pipeline;
      if (nodes.length) { hideEmpty(); renderCanvas(); }
    } catch(e) {}
  }
  // Seed default pipeline for demo
  if (!nodes.length) {
    ['planner','developer','tester','reviewer_stateless'].forEach(r => {
      const def = JSON.parse(JSON.stringify(ROLE_DEFAULTS[r]));
      def.id = uid(); def.role = r;
      nodes.push(def);
    });
    hideEmpty();
    renderCanvas();
  }
});

// Click outside deselects
document.getElementById('canvasScroll').addEventListener('click', (e) => {
  if (e.target === e.currentTarget || e.target.id === 'pipelineFlow') closeDetail();
});
</script>
